class MultiFor {
 public static void main(String [] args) {
 for(int x = 0; x < 4; x++) {

 for(int y = 4; y > 2; y--) {
 System.out.println(x + “ “ + y);
 }
 if (x == 1) { What would happen
 x++; if this code block came 
 } before the ‘y’ for loop?
 }
 }
}
class Output {
 public static void main(String [] args) {
 Output 0 = new Output();
 o.go();
 }
 void go() {
 int y = 7;
 for(int x = 1; x < 8; x++) {
 y++;
 if (x > 4) {
 System.out.print(++y + “ “);
 }
 if (y > 14) {
 System.out.println(“ x = “ + x);
 break;
 }
 }
 }
} Did you remember to factor in the
 break statement? How did that 

 affect the output?
